async function getUser(id: string): Promise<User> {
  const key = `user:${id}`;
  const cached = await redis.get(key);
  if (cached) return JSON.parse(cached);

  const user = await db.users.findById(id); // cache miss -> DB
  if (user) {
    // Always set a TTL so a stale/forgotten key self-heals.
    await redis.set(key, JSON.stringify(user), 'EX', 300);
  }
  return user;
}

async function updateUser(id: string, patch: Partial<User>): Promise<void> {
  await db.users.update(id, patch);
  // Invalidate, do NOT write-through here: avoids a stale write racing the DB.
  await redis.del(`user:${id}`);
}

// Sliding-window rate limit: max `limit` requests per `windowMs`.
async function allow(userId: string, limit: number, windowMs: number): Promise<boolean> {
  const key = `rl:${userId}`;
  const now = Date.now();
  const member = `${now}-${Math.random()}`; // unique to avoid score collisions
  const results = await redis
    .multi()
    .zremrangebyscore(key, 0, now - windowMs) // drop events outside window
    .zadd(key, now, member)                   // record this request
    .zcard(key)                               // count events in window
    .pexpire(key, windowMs)                   // let the key self-clean
    .exec();
  const count = results[2][1] as number;
  return count <= limit;
}

// Cache-aside with stampede protection via a per-key lock + jittered TTL.
async function getWithLock<T>(key: string, ttl: number, load: () => Promise<T>): Promise<T> {
  const hit = await redis.get(key);
  if (hit) return JSON.parse(hit);

  const lockKey = `lock:${key}`;
  const token = crypto.randomUUID();
  const gotLock = await redis.set(lockKey, token, 'NX', 'PX', 5000);

  if (!gotLock) {
    // Someone else is recomputing. Back off briefly and read the fresh value.
    await sleep(50 + Math.random() * 100);
    const retry = await redis.get(key);
    if (retry) return JSON.parse(retry);
    return load(); // fallback: very rare, lock holder died
  }

  try {
    const value = await load();
    const jitter = Math.floor(ttl * 0.2 * Math.random());
    await redis.set(key, JSON.stringify(value), 'EX', ttl + jitter);
    return value;
  } finally {
    // Release only if we still own the lock (avoid deleting someone else's).
    await redis.eval(
      "if redis.call('get', KEYS[1]) == ARGV[1] then return redis.call('del', KEYS[1]) else return 0 end",
      1, lockKey, token,
    );
  }
}

// BEFORE: flat TTL -> synchronized expiry, no stampede protection.
async function getProductBad(id: string) {
  const k = `product:${id}`;
  const c = await redis.get(k);
  if (c) return JSON.parse(c);
  const p = await loadProductExpensive(id); // heavy join + pricing call
  await redis.set(k, JSON.stringify(p), 'EX', 600); // every key dies together
  return p;
}

// AFTER: jittered TTL + per-key lock + serve-stale on lock contention.
async function getProductGood(id: string) {
  const k = `product:${id}`;
  const c = await redis.get(k);
  if (c) return JSON.parse(c);
  const lockKey = `lock:${k}`;
  const token = crypto.randomUUID();
  if (await redis.set(lockKey, token, 'NX', 'PX', 4000)) {
    try {
      const p = await loadProductExpensive(id);
      const ttl = 600 + Math.floor(Math.random() * 120); // +0..20% jitter
      await redis.set(k, JSON.stringify(p), 'EX', ttl);
      return p;
    } finally {
      await releaseLock(lockKey, token);
    }
  }
  await sleep(75);
  const again = await redis.get(k);
  return again ? JSON.parse(again) : loadProductExpensive(id);
}

