import Redis from 'ioredis';

const redis = new Redis();
const sleep = (ms: number) => new Promise((r) => setTimeout(r, ms));

// Atomic release: only delete the lock if we still own it.
const RELEASE = `
  if redis.call('get', KEYS[1]) == ARGV[1] then
    return redis.call('del', KEYS[1])
  else
    return 0
  end`;

export async function getOrLoad<T>(
  key: string,
  ttlSeconds: number,
  loader: () => Promise<T>,
): Promise<T> {
  // 1. Fast path: cache hit.
  const hit = await redis.get(key);
  if (hit !== null) return JSON.parse(hit) as T;

  const lockKey = `lock:${key}`;
  const token = crypto.randomUUID();
  const maxWaitMs = 5000;
  const deadline = Date.now() + maxWaitMs;

  // 2. Try to become the single recomputer.
  const acquired = await redis.set(lockKey, token, 'PX', 4000, 'NX');

  if (acquired === 'OK') {
    try {
      const value = await loader(); // only ONE caller reaches here per key
      const jitter = Math.floor(ttlSeconds * 0.2 * Math.random());
      await redis.set(key, JSON.stringify(value), 'EX', ttlSeconds + jitter);
      return value;
    } finally {
      await redis.eval(RELEASE, 1, lockKey, token); // atomic, owner-checked
    }
  }

  // 3. Loser path: wait for the holder to populate, then read.
  while (Date.now() < deadline) {
    await sleep(40 + Math.floor(Math.random() * 80)); // jittered backoff
    const filled = await redis.get(key);
    if (filled !== null) return JSON.parse(filled) as T;
    // If the lock is gone but key still empty, holder likely died -> retry to grab it.
    const lockStillHeld = await redis.exists(lockKey);
    if (!lockStillHeld) return getOrLoad(key, ttlSeconds, loader);
  }

  // 4. Last resort after timeout: load directly so the caller never hangs.
  return loader();
}

import Redis from 'ioredis';

const redis = new Redis();

// Lua keeps the whole check atomic, avoiding races between trim/add/count.
const SCRIPT = `
  local key     = KEYS[1]
  local now     = tonumber(ARGV[1])
  local window  = tonumber(ARGV[2])
  local limit   = tonumber(ARGV[3])
  local member  = ARGV[4]

  -- 1. Drop events outside the sliding window.
  redis.call('ZREMRANGEBYSCORE', key, 0, now - window)
  -- 2. How many remain inside the window?
  local count = redis.call('ZCARD', key)
  if count < limit then
    -- 3. Admit: record this request and refresh the key TTL.
    redis.call('ZADD', key, now, member)
    redis.call('PEXPIRE', key, window)
    return 1   -- allowed
  end
  -- Refresh TTL even when rejecting so the key still self-cleans.
  redis.call('PEXPIRE', key, window)
  return 0     -- denied
`;

export async function rateLimit(
  userId: string,
  limit: number,
  windowMs: number,
): Promise<boolean> {
  const key = `rl:${userId}`;
  const now = Date.now();
  const member = `${now}-${crypto.randomUUID()}`; // unique per request
  const allowed = (await redis.eval(
    SCRIPT, 1, key, String(now), String(windowMs), String(limit), member,
  )) as number;
  return allowed === 1;
}
